UPDATE core_vocabulary SET word = 'find', meaning_zh = '找到；发现；认为', definition_en = 'to discover something by looking, trying, or learning', primary_part_of_speech = 'verb', phonetic_us = '/faɪnd/', phonetic_uk = '/faɪnd/', updated_at = CURRENT_TIMESTAMP WHERE id = 'find';
